function isConsoleAvailable() {
    return typeof console !== "undefined" && typeof console.warn === "function";
}
function isConsoleErrorAvailable() {
    return typeof console !== "undefined" && typeof console.error === "function";
}
export function logWarn(context, message) {
    if (isConsoleAvailable()) {
        console.warn(`[${context}] ${message}`);
    }
}
export function logError(context, message, error) {
    if (isConsoleErrorAvailable()) {
        if (error !== undefined) {
            console.error(`[${context}] ${message}`, error);
        }
        else {
            console.error(`[${context}] ${message}`);
        }
    }
}
